import React, { useEffect, useState } from "react";
import { Table, Button, Space, Input, Card, Tag, Tooltip } from "antd";
import { BiSearch, BiShow } from "react-icons/bi";
import { useDispatch, useSelector } from "react-redux";
import { getActivities } from "../../features/Activity/ActivitySlice";
import { Link } from "react-router-dom";
import Loading from "../../utils/Loading.js";

const RoleBasedActivity = ({ role }) => {
  const dispatch = useDispatch();
  const {
    activityLogs = [],
    loading,
    error,
  } = useSelector((state) => state.activity);
  const [searchText, setSearchText] = useState("");

  useEffect(() => {
    if (role) {
      dispatch(getActivities({ role }));
    }
  }, [dispatch, role]);

  const getActionTag = (action) => {
    const act = action.toLowerCase();
    if (act.includes("delete") || act.includes("remove"))
      return (
        <Tag
          color="error"
          className="rounded-full px-3 uppercase font-bold text-[10px]"
        >
          Deletion
        </Tag>
      );
    if (act.includes("update") || act.includes("edit"))
      return (
        <Tag
          color="warning"
          className="rounded-full px-3 uppercase font-bold text-[10px]"
        >
          Revision
        </Tag>
      );
    if (act.includes("add") || act.includes("create"))
      return (
        <Tag
          color="success"
          className="rounded-full px-3 uppercase font-bold text-[10px]"
        >
          Creation
        </Tag>
      );
    return (
      <Tag
        color="default"
        className="rounded-full px-3 uppercase font-bold text-[10px]"
      >
        Activity
      </Tag>
    );
  };

  const columns = [
    {
      title: "#ORDINAL",
      dataIndex: "key",
      render: (text) => (
        <span className="font-mono text-[10px] font-black text-gray-400">
          ACT-{text}
        </span>
      ),
      width: 100,
    },
    {
      title: "OPERATIONAL ACTION",
      dataIndex: "action",
      render: (text) => (
        <Space direction="vertical" size={0}>
          {getActionTag(text)}
          <span className="font-black text-gray-900 tracking-tight uppercase text-xs mt-1">
            {text}
          </span>
        </Space>
      ),
      sorter: (a, b) => a.action.localeCompare(b.action),
    },
    {
      title: "TEMPORAL MARK (TIMESTAMP)",
      dataIndex: "timestamp",
      render: (date) => (
        <span className="text-gray-500 font-medium text-[11px] uppercase tracking-tight">
          {new Date(date).toLocaleString("en-GB", {
            day: "2-digit",
            month: "short",
            year: "numeric",
            hour: "2-digit",
            minute: "2-digit",
            second: "2-digit",
          })}
        </span>
      ),
      sorter: (a, b) => new Date(a.timestamp) - new Date(b.timestamp),
    },
    {
      title: "SYSTEM TRACE (DETAILS)",
      dataIndex: "details",
      render: (_, record) => (
        <Link to={`/superAdmin/activitylog/${record._id}`}>
          <Button
            type="text"
            icon={<BiShow size={18} />}
            className="text-blue-600 hover:text-blue-700 flex items-center gap-2 font-bold text-xs uppercase tracking-tight"
          >
            Trace Activity
          </Button>
        </Link>
      ),
    },
  ];

  const filteredData =
    activityLogs
      ?.filter(
        (log) =>
          !searchText ||
          log.action.toLowerCase().includes(searchText.toLowerCase()),
      )
      .map((log, i) => ({
        ...log,
        key: i + 1,
      })) || [];

  if (error)
    return (
      <div className="p-8 text-center bg-red-50 rounded-2xl border border-red-100">
        <h3 className="text-red-800 font-black uppercase tracking-widest text-xs mb-2">
          System Error
        </h3>
        <p className="text-red-600 font-medium tracking-tight">
          {error.message}
        </p>
      </div>
    );

  return (
    <div className="p-8 space-y-8 animate-in fade-in duration-500">
      {/* Header Section */}
      <div className="flex justify-between items-end border-b border-gray-100 pb-6">
        <div>
          <h1 className="text-3xl font-black text-gray-900 tracking-tight">
            {role.toUpperCase()} AUDIT TRAIL
          </h1>
          <p className="text-gray-500 font-medium tracking-tight">
            Comprehensive Operational Logs •{" "}
            {role.charAt(0).toUpperCase() + role.slice(1)} Accountability
          </p>
        </div>
        <div className="flex gap-4">
          <Input
            prefix={<BiSearch className="text-gray-400" />}
            placeholder="Search Audit Trail..."
            className="rounded-xl border-gray-100 w-72 h-11 shadow-sm"
            onChange={(e) => setSearchText(e.target.value)}
          />
        </div>
      </div>

      <div className="enterprise-card bg-white p-4">
        <Table
          columns={columns}
          dataSource={filteredData}
          loading={{ spinning: loading, tip: "Synchronizing Audit Logs..." }}
          pagination={{
            pageSize: 12,
            showSizeChanger: true,
            className: "enterprise-pagination",
          }}
          className="enterprise-table super-modern-table"
          scroll={{ x: 1000 }}
        />
      </div>
    </div>
  );
};

export default RoleBasedActivity;
